{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires logical rule chaining through a large set of rules. To avoid errors, the process must be broken down into rule extraction, dependency mapping, and path validation.",
  "helpers": [
    {
      "label": "rule_extraction_and_entity_mapping",
      "instructions": "Identify all rules involving the 'butterfly', the 'fish', and the 'secret'. List every rule that acts as a prerequisite or a consequence for these specific entities or the 'secret' state."
    },
    {
      "label": "dependency_graph_construction",
      "instructions": "Construct a directed graph where nodes are game states/entities and edges are the rules. Specifically, trace all possible paths starting from any initial state that could lead to 'butterfly reveals secret' or 'fish learns secret'."
    },
    {
      "label": "logical_chain_validation",
      "instructions": "Analyze the constructed paths to determine if there is a deterministic chain of rules that leads to the specific outcome: 'butterfly reveals a secret to the fish'. Check for missing links, conditional requirements (if/then) that are not met, or circular logic that prevents the conclusion."
    }
  ],
  "synthesis_brief": "Combine the extracted rules and the dependency graph to see if a complete, unbroken logical chain exists from the starting conditions to the target event. If the chain is broken, contains unfulfilled conditions, or leads to multiple conflicting outcomes, the answer must be 'unknown'."
}
```

